const checkpoints = [];

function safeParse(key) {
  const raw = localStorage.getItem(key);
  if (!raw) return Array.isArray([]) ? [] : null;
  try { return JSON.parse(raw); } catch (e) { return Array.isArray([]) ? [] : null; }
}

const categories = safeParse('categories') || [];
const discussions = safeParse('discussions') || [];
const tags = safeParse('tags') || [];

// Build lookup maps
const categoriesById = {};
for (let c of categories) { if (c && c.id) categoriesById[c.id] = c; }
const tagsById = {};
for (let t of tags) { if (t && t.id) tagsById[t.id] = t; }

// Helper: count sentences naively by punctuation
function countSentences(text) {
  if (!text || typeof text !== 'string') return 0;
  const parts = text.split(/[.!?]+/).map(s => s.trim()).filter(s => s.length > 0);
  return parts.length;
}

// Find discussions that match the requested title and category
const targetTitle = 'Best resources to learn responsive design?';
const qualifying = [];
for (let d of discussions) {
  if (!d || !d.title || !d.body) continue;
  if (d.title !== targetTitle) continue;
  const cat = categoriesById[d.categoryId];
  if (!cat || cat.slug !== 'web_development') continue;
  // Topic about responsive design: check phrase in title or body
  const bodyLower = (d.body || '').toLowerCase();
  const titleLower = (d.title || '').toLowerCase();
  if (titleLower.indexOf('responsive') === -1 && bodyLower.indexOf('responsive') === -1) continue;
  qualifying.push(d);
}

// From these, find ones with exactly the two required tags and subscription+min sentences
let taggedAndSubscribed = [];
for (let d of qualifying) {
  const tagIds = Array.isArray(d.tagIds) ? d.tagIds : [];
  if (tagIds.length !== 2) continue;
  const tagNames = tagIds.map(id => tagsById[id] ? tagsById[id].name : null).filter(Boolean);
  // Require exactly CSS and Responsive Design (order-insensitive)
  const required = ['CSS', 'Responsive Design'];
  const sortedTagNames = tagNames.slice().sort();
  const sortedReq = required.slice().sort();
  const tagsMatch = sortedTagNames.length === sortedReq.length && sortedTagNames.every((v, i) => v === sortedReq[i]);
  if (!tagsMatch) continue;
  const sentenceCount = countSentences(d.body);
  if (sentenceCount < 3) continue;
  if (!d.isSubscribed) continue;
  taggedAndSubscribed.push(d);
}

// CP1 (0.3): At least one discussion with the exact title in Web Development about responsive design
checkpoints.push({ passed: qualifying.length > 0, weight: 0.3 });
// CP2 (0.3): Among those, at least one has exactly the CSS and Responsive Design tags
checkpoints.push({ passed: taggedAndSubscribed.length > 0, weight: 0.3 });
// CP3 (0.4): That same qualifying discussion also has subscription enabled and body >= 3 sentences (already filtered into taggedAndSubscribed)
checkpoints.push({ passed: taggedAndSubscribed.length > 0, weight: 0.4 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function safeParse(key, fallback) {
  const raw = localStorage.getItem(key);
  if (!raw) return typeof fallback === 'undefined' ? null : fallback;
  try { return JSON.parse(raw); } catch (e) { return typeof fallback === 'undefined' ? null : fallback; }
}

const searchParams = safeParse('task2_searchParams', null);
const selectedDiscussionId = localStorage.getItem('task2_selectedDiscussionId') || null;
const discussions = safeParse('discussions', [] ) || [];
const posts = safeParse('posts', [] ) || [];
const reactions = safeParse('reactions', [] ) || [];
const tags = safeParse('tags', [] ) || [];

const tagsById = {};
for (let t of tags) { if (t && t.id) tagsById[t.id] = t; }

function matchesQuery(d, query) {
  if (!d) return false;
  const q = (query || '').toLowerCase().trim();
  if (!q) return false;
  const title = (d.title || '').toLowerCase();
  const body = (d.body || '').toLowerCase();
  if (title.indexOf(q) !== -1 || body.indexOf(q) !== -1) return true;
  if (Array.isArray(d.tagIds)) {
    for (let id of d.tagIds) {
      const tag = tagsById[id];
      const name = tag && tag.name ? tag.name.toLowerCase() : '';
      if (name.indexOf(q) !== -1) return true;
    }
  }
  return false;
}

// Compute top most-upvoted qualifying discussion as per task filters (query + minReplies)
const query = 'JavaScript arrays';
const qualifying = discussions.filter(d => {
  if (!d) return false;
  const rc = d.replyCount || 0;
  if (rc < 5) return false;
  if (!matchesQuery(d, query)) return false;
  return true;
});

let topDiscussion = null;
if (qualifying.length > 0) {
  const sorted = qualifying.slice().sort((a, b) => {
    const sa = a.score || 0;
    const sb = b.score || 0;
    return sb - sa;
  });
  topDiscussion = sorted[0];
}

const selectedDiscussion = discussions.find(d => d && d.id === selectedDiscussionId) || null;
const opPost = selectedDiscussion ? posts.find(p => p && p.discussionId === selectedDiscussion.id && p.isOriginalPost) || null : null;

// CP1 (0.30): User used correct search parameters (query, date range, min replies, sortBy)
let cp1Passed = false;
if (searchParams && typeof searchParams === 'object') {
  const qOk = typeof searchParams.query === 'string' && searchParams.query.toLowerCase().trim() === query.toLowerCase();
  const filters = searchParams.filters || {};
  const dateOk = filters.dateRange === 'last_6_months';
  const repliesOk = typeof filters.minReplies === 'number' && filters.minReplies >= 5;
  const sortOk = searchParams.sortBy === 'most_upvoted';
  cp1Passed = qOk && dateOk && repliesOk && sortOk;
}
checkpoints.push({ passed: cp1Passed, weight: 0.30 });

// CP2 (0.35): User opened the top most-upvoted qualifying discussion
const cp2Passed = !!(topDiscussion && selectedDiscussion && selectedDiscussion.id === topDiscussion.id);
checkpoints.push({ passed: cp2Passed, weight: 0.35 });

// CP3 (0.35): For that selected discussion, original post has an upvote recorded and the discussion is bookmarked
let cp3Passed = false;
if (selectedDiscussion && opPost) {
  const hasUpvote = (opPost.upvoteCount || 0) > 0 || reactions.some(r => r && r.postId === opPost.id && r.reactionType === 'upvote');
  const isBookmarked = !!selectedDiscussion.isBookmarked;
  cp3Passed = hasUpvote && isBookmarked;
}
checkpoints.push({ passed: cp3Passed, weight: 0.35 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function safeParse(key, fallback) {
  const raw = localStorage.getItem(key);
  if (!raw) return typeof fallback === 'undefined' ? null : fallback;
  try { return JSON.parse(raw); } catch (e) { return typeof fallback === 'undefined' ? null : fallback; }
}

const discussions = safeParse('discussions', [] ) || [];
const posts = safeParse('posts', [] ) || [];
const reactions = safeParse('reactions', [] ) || [];
const accountSettings = safeParse('account_settings', null) || {};
const myName = accountSettings.displayName || 'sample_user';

function trendingScore(d) {
  if (!d) return 0;
  const score = d.score || 0;
  const replies = d.replyCount || 0;
  const views = d.viewCount || 0;
  return score * 2 + replies + views * 0.1;
}

// Find top trending discussion
let topDiscussion = null;
if (discussions.length > 0) {
  const sorted = discussions.slice().sort((a, b) => trendingScore(b) - trendingScore(a));
  topDiscussion = sorted[0];
}

let cp1Passed = false;
if (topDiscussion) {
  const threadPosts = posts.filter(p => p && p.discussionId === topDiscussion.id);
  const replies = threadPosts.filter(p => p && !p.isOriginalPost);

  // Replies authored by current user that reply to other users' posts
  const myReplies = replies.filter(p => p.authorDisplayName === myName);

  // Build map of posts by id
  const postById = {};
  for (let p of threadPosts) { if (p && p.id) postById[p.id] = p; }

  const candidateMyReplies = [];
  for (let r of myReplies) {
    if (!r.parentPostId) continue; // must reply to a specific post
    const parent = postById[r.parentPostId];
    if (!parent) continue;
    if (parent.authorDisplayName === myName) continue; // must be different user
    candidateMyReplies.push({ reply: r, parent: parent });
  }

  if (candidateMyReplies.length >= 2) {
    // Unique parent authors
    const parentAuthors = new Set(candidateMyReplies.map(x => x.parent.authorDisplayName));
    const distinctParents = parentAuthors.size >= 2;

    // At least one reply with @-mention at start and sufficient sentences across two replies
    function countSentences(text) {
      if (!text || typeof text !== 'string') return 0;
      const parts = text.split(/[.!?]+/).map(s => s.trim()).filter(s => s.length > 0);
      return parts.length;
    }

    let hasMention = false;
    let firstTwoGood = false;
    // Take first two candidate replies
    const r1 = candidateMyReplies[0].reply;
    const r2 = candidateMyReplies[1].reply;
    if (r1 && r2) {
      const s1 = countSentences(r1.body || '');
      const s2 = countSentences(r2.body || '');
      // One must have >=2 sentences, the other at least 1
      const sentencesOk = (s1 >= 2 && s2 >= 1) || (s2 >= 2 && s1 >= 1);
      hasMention = [r1, r2].some(r => typeof r.body === 'string' && r.body.trim().startsWith('@'));
      firstTwoGood = sentencesOk && hasMention;
    }

    cp1Passed = distinctParents && firstTwoGood;
  }
}

// CP1 (0.40): In top trending discussion, user replied to posts from two different other users, with one reply starting with an @-mention and adequate sentence counts
checkpoints.push({ passed: cp1Passed, weight: 0.40 });

// CP2 (0.60): User liked exactly three different replies from three unique other users in that discussion
let cp2Passed = false;
if (topDiscussion) {
  const threadPosts = posts.filter(p => p && p.discussionId === topDiscussion.id);
  const replies = threadPosts.filter(p => p && !p.isOriginalPost);
  const postById = {};
  for (let p of threadPosts) { if (p && p.id) postById[p.id] = p; }

  const likeReactions = reactions.filter(r => r && r.reactionType === 'like');
  const likedReplyPostIds = [];

  for (let r of likeReactions) {
    const p = postById[r.postId];
    if (!p) continue;
    if (p.isOriginalPost) continue; // must be replies
    if (p.authorDisplayName === myName) continue; // exclude own posts
    likedReplyPostIds.push(p.id);
  }

  const uniqueLikedIds = Array.from(new Set(likedReplyPostIds));

  if (uniqueLikedIds.length === 3) {
    const authors = new Set();
    let allDistinctAuthors = true;
    for (let id of uniqueLikedIds) {
      const p = postById[id];
      if (!p) { allDistinctAuthors = false; break; }
      const author = p.authorDisplayName;
      if (authors.has(author)) { allDistinctAuthors = false; break; }
      authors.add(author);
    }
    cp2Passed = allDistinctAuthors;
  }
}

checkpoints.push({ passed: cp2Passed, weight: 0.60 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

