const tags = safeParse('tags', [] ) || [];
const followed = tags.filter(t => t && t.isFollowed);

const uxTopics = followed.filter(t => {
  const name = (t.name || '').toLowerCase();
  return (t.followerCount || 0) >= 500 && (name.indexOf('ux') !== -1);
});

const reactTopics = followed.filter(t => {
  const name = (t.name || '').toLowerCase();
  return (t.followerCount || 0) >= 500 && (name.indexOf('react') !== -1);
});

const careerTopics = followed.filter(t => {
  const name = (t.name || '').toLowerCase();
  return (t.followerCount || 0) >= 500 && (name.indexOf('career') !== -1);
});

// CP1 (0.33): At least one qualifying UX design topic followed
checkpoints.push({ passed: uxTopics.length >= 1, weight: 0.33 });
// CP2 (0.33): At least one qualifying React topic followed
checkpoints.push({ passed: reactTopics.length >= 1, weight: 0.33 });
// CP3 (0.34): At least one qualifying career advice topic followed AND total followed topics is exactly 3
checkpoints.push({ passed: careerTopics.length >= 1 && followed.length === 3, weight: 0.34 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function safeParse(key, fallback) {
  const raw = localStorage.getItem(key);
  if (!raw) return typeof fallback === 'undefined' ? null : fallback;
  try { return JSON.parse(raw); } catch (e) { return typeof fallback === 'undefined' ? null : fallback; }
}

const discussions = safeParse('discussions', [] ) || [];
const posts = safeParse('posts', [] ) || [];
const memberProfiles = safeParse('member_profiles', [] ) || [];
const privateMessages = safeParse('private_messages', [] ) || [];
const reactions = safeParse('reactions', [] ) || [];

const profilesById = {};
for (let m of memberProfiles) { if (m && m.id) profilesById[m.id] = m; }

// Helper: count sentences
function countSentences(text) {
  if (!text || typeof text !== 'string') return 0;
  const parts = text.split(/[.!?]+/).map(s => s.trim()).filter(s => s.length > 0);
  return parts.length;
}

// Find discussions about portfolios in the Career & Growth category
const portfolioDiscussions = discussions.filter(d => {
  if (!d) return false;
  const title = (d.title || '').toLowerCase();
  const body = (d.body || '').toLowerCase();
  const hasPortfolio = title.indexOf('portfolio') !== -1 || body.indexOf('portfolio') !== -1;
  return hasPortfolio;
});

// Collect qualifying replies (in those discussions) with at least one like
const qualifyingReplyAuthorIds = new Set();
for (let d of portfolioDiscussions) {
  const threadReplies = posts.filter(p => p && p.discussionId === d.id && !p.isOriginalPost);
  for (let p of threadReplies) {
    const likeCount = p.likeCount || 0;
    const hasReactionLike = reactions.some(r => r && r.postId === p.id && r.reactionType === 'like');
    if (likeCount >= 1 || hasReactionLike) {
      if (p.authorProfileId) {
        qualifyingReplyAuthorIds.add(p.authorProfileId);
      }
    }
  }
}

// Messages with exact subject and valid body (3-5 sentences, no external links)
const targetSubject = 'Request for portfolio feedback';
const candidateMessages = privateMessages.filter(m => {
  if (!m) return false;
  if (m.subject !== targetSubject) return false;
  const body = m.body || '';
  const sentences = countSentences(body);
  if (sentences < 3 || sentences > 5) return false;
  const tokens = body.split(/\s+/);
  const hasLink = tokens.some(t => t.startsWith('http://') || t.startsWith('https://'));
  if (hasLink) return false;
  return true;
});

// CP1 (0.40): At least one message with exact subject, 3–5 sentences, and no external links
checkpoints.push({ passed: candidateMessages.length > 0, weight: 0.40 });

// CP2 (0.60): At least one such message was sent to an author of a liked reply in a portfolio discussion
let cp2Passed = false;
for (let m of candidateMessages) {
  if (qualifyingReplyAuthorIds.has(m.recipientProfileId)) {
    cp2Passed = true;
    break;
  }
}
checkpoints.push({ passed: cp2Passed, weight: 0.60 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

