const settings = safeParse('account_settings', null) || {};

// Helper: count words
function countWords(text) {
  if (!text || typeof text !== 'string') return 0;
  const parts = text.trim().split(/\s+/).filter(w => w.length > 0);
  return parts.length;
}

// CP1 (0.30): Display name exactly 'Alex UX Researcher'
const cp1Passed = settings.displayName === 'Alex UX Researcher';
checkpoints.push({ passed: cp1Passed, weight: 0.30 });

// CP2 (0.40): Bio between 20 and 30 words inclusive
const bioWords = countWords(settings.bio || '');
const cp2Passed = bioWords >= 20 && bioWords <= 30;
checkpoints.push({ passed: cp2Passed, weight: 0.40 });

// CP3 (0.30): Timezone corresponds to GMT+1/UTC+1 (stored as 'utc_plus_1') and daily summary is enabled
const cp3Passed = settings.timezone === 'utc_plus_1' && !!settings.dailySummaryEnabled;
checkpoints.push({ passed: cp3Passed, weight: 0.30 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function safeParse(key, fallback) {
  const raw = localStorage.getItem(key);
  if (!raw) return typeof fallback === 'undefined' ? null : fallback;
  try { return JSON.parse(raw); } catch (e) { return typeof fallback === 'undefined' ? null : fallback; }
}

const reports = safeParse('content_reports', [] ) || [];
const posts = safeParse('posts', [] ) || [];
const discussions = safeParse('discussions', [] ) || [];

const discussionsById = {};
for (let d of discussions) { if (d && d.id) discussionsById[d.id] = d; }

// Identify valid spam-target posts: in a discussion whose title includes 'spam', contains link, 0 upvotes
const validSpamPostIds = new Set();
for (let p of posts) {
  if (!p) continue;
  if (!p.containsLink) continue;
  const upvotes = p.upvoteCount || 0;
  if (upvotes !== 0) continue;
  const disc = discussionsById[p.discussionId];
  if (!disc) continue;
  const title = (disc.title || '').toLowerCase();
  if (title.indexOf('spam') === -1) continue;
  validSpamPostIds.add(p.id);
}

let matchedReport = null;
for (let r of reports) {
  if (!r) continue;
  if (r.reason !== 'spam') continue;
  if (!validSpamPostIds.has(r.postId)) continue;
  matchedReport = r;
  break;
}

// CP1 (0.60): A spam report was submitted for a reply that contains a link, has 0 upvotes, and is in a discussion with 'spam' in the title
const cp1Passed = !!matchedReport;
checkpoints.push({ passed: cp1Passed, weight: 0.60 });

// CP2 (0.40): The spam report note matches the expected phrasing about an unsolicited promotional link
const cp2Passed = !!(matchedReport && matchedReport.note === 'Contains unsolicited promotional link');
checkpoints.push({ passed: cp2Passed, weight: 0.40 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);

const checkpoints = [];

function safeParse(key, fallback) {
  const raw = localStorage.getItem(key);
  if (!raw) return typeof fallback === 'undefined' ? null : fallback;
  try { return JSON.parse(raw); } catch (e) { return typeof fallback === 'undefined' ? null : fallback; }
}

const categories = safeParse('categories', [] ) || [];
const discussions = safeParse('discussions', [] ) || [];
const polls = safeParse('polls', [] ) || [];
const pollOptions = safeParse('poll_options', [] ) || [];

const categoriesById = {};
for (let c of categories) { if (c && c.id) categoriesById[c.id] = c; }

function countSentences(text) {
  if (!text || typeof text !== 'string') return 0;
  const parts = text.split(/[.!?]+/).map(s => s.trim()).filter(s => s.length > 0);
  return parts.length;
}

const targetTitle = 'Which feature should we prioritize next?';
const targetQuestion = 'What should we build next?';
const requiredOptions = ['Dark mode', 'Mobile app improvements', 'Advanced search filters'];

// Find qualifying discussions in Product Feedback
const qualifyingDiscussions = [];
for (let d of discussions) {
  if (!d || !d.title || !d.body) continue;
  if (d.title !== targetTitle) continue;
  const cat = categoriesById[d.categoryId];
  if (!cat || cat.slug !== 'product_feedback') continue;
  if (!d.hasPoll) continue;
  const sentences = countSentences(d.body);
  if (sentences < 2) continue;
  qualifyingDiscussions.push(d);
}

// CP1 (0.40): At least one discussion in Product Feedback with the exact title, hasPoll=true, and body >= 2 sentences
checkpoints.push({ passed: qualifyingDiscussions.length > 0, weight: 0.40 });

let pollOk = false;
let optionsOk = false;

if (qualifyingDiscussions.length > 0) {
  for (let d of qualifyingDiscussions) {
    const poll = polls.find(p => p && p.discussionId === d.id) || null;
    if (!poll) continue;
    // Check poll question, single-choice, and ~7-day duration
    const qOk = poll.question === targetQuestion;
    const singleChoiceOk = poll.multipleChoiceAllowed === false;
    let durationOk = false;
    if (poll.startAt && poll.endAt) {
      const start = new Date(poll.startAt);
      const end = new Date(poll.endAt);
      if (!isNaN(start.getTime()) && !isNaN(end.getTime())) {
        const ms = end.getTime() - start.getTime();
        const days = ms / (1000 * 60 * 60 * 24);
        // Allow slight rounding differences around 7 days
        durationOk = days >= 6.5 && days <= 7.5;
      }
    }
    const opts = pollOptions.filter(o => o && o.pollId === poll.id);
    const texts = opts.map(o => o.optionText);
    const sortedTexts = texts.slice().sort();
    const sortedReq = requiredOptions.slice().sort();
    const optionsExact = sortedTexts.length === sortedReq.length && sortedTexts.every((v, i) => v === sortedReq[i]);

    if (qOk && singleChoiceOk && durationOk) {
      pollOk = true;
    }
    if (optionsExact && opts.length === 3) {
      optionsOk = true;
    }
    if (pollOk && optionsOk) break;
  }
}

// CP2 (0.30): Attached poll has the correct question, is single-choice, and lasts ~7 days
checkpoints.push({ passed: pollOk, weight: 0.30 });
// CP3 (0.30): Poll has exactly three options with the required labels
checkpoints.push({ passed: optionsOk, weight: 0.30 });

return checkpoints.reduce((sum, cp) => sum + (cp.passed ? cp.weight : 0), 0);
